class Solution {
public:
    long long minSumSquareDiff(vector<int>& nums1, vector<int>& nums2, int k1, int k2) {
        int n = nums1.size();
        vector<long long> diff(n);
        for (int i = 0; i < n; ++i) {
            diff[i] = abs((long long)nums1[i] - nums2[i]);
        }
        long long total = 0;
        for (long long d : diff) total += d * d;
        int k = k1 + k2;
        if (k >= total) return 0;
        sort(diff.begin(), diff.end(), greater<long long>());
        diff.push_back(0);
        for (int i = 0; i < n; ++i) {
            long long d = diff[i] - diff[i + 1];
            if (d * (i + 1) <= k) {
                k -= d * (i + 1);
                total -= (diff[i] * diff[i] - diff[i + 1] * diff[i + 1]) * (i + 1);
            } else {
                int t = k / (i + 1);
                total -= (diff[i] * diff[i] - (diff[i] - t) * (diff[i] - t)) * (i + 1);
                k -= t * (i + 1);
                for (int j = 0; j < k; ++j) total -= 2 * (diff[i] - t) + 1;
                break;
            }
        }
        return total;
    }
};
